'dfp_read_field_def_openpoker.v1.TableEvent.DealtCards'(Other, Z1, Z2, F, F@_1, F@_2, TrUserData) -> 'dg_read_field_def_openpoker.v1.TableEvent.DealtCards'(Other, Z1, Z2, F, F@_1, F@_2, TrUserData).

'dg_read_field_def_openpoker.v1.TableEvent.DealtCards'(<<1:1, X:7, Rest/binary>>, N, Acc, F, F@_1, F@_2, TrUserData) when N < 32 - 7 -> 'dg_read_field_def_openpoker.v1.TableEvent.DealtCards'(Rest, N + 7, X bsl N + Acc, F, F@_1, F@_2, TrUserData);
'dg_read_field_def_openpoker.v1.TableEvent.DealtCards'(<<0:1, X:7, Rest/binary>>, N, Acc, _, F@_1, F@_2, TrUserData) ->
    Key = X bsl N + Acc,
    case Key of
        10 -> 'd_field_openpoker.v1.TableEvent.DealtCards_player_id'(Rest, 0, 0, 0, F@_1, F@_2, TrUserData);
        18 -> 'd_field_openpoker.v1.TableEvent.DealtCards_card_string'(Rest, 0, 0, 0, F@_1, F@_2, TrUserData);
        _ ->
            case Key band 7 of
                0 -> 'skip_varint_openpoker.v1.TableEvent.DealtCards'(Rest, 0, 0, Key bsr 3, F@_1, F@_2, TrUserData);
                1 -> 'skip_64_openpoker.v1.TableEvent.DealtCards'(Rest, 0, 0, Key bsr 3, F@_1, F@_2, TrUserData);
                2 -> 'skip_length_delimited_openpoker.v1.TableEvent.DealtCards'(Rest, 0, 0, Key bsr 3, F@_1, F@_2, TrUserData);
                3 -> 'skip_group_openpoker.v1.TableEvent.DealtCards'(Rest, 0, 0, Key bsr 3, F@_1, F@_2, TrUserData);
                5 -> 'skip_32_openpoker.v1.TableEvent.DealtCards'(Rest, 0, 0, Key bsr 3, F@_1, F@_2, TrUserData)
            end
    end;
