'skip_length_delimited_openpoker.v1.TableEvent.DealtCards'(<<1:1, X:7, Rest/binary>>, N, Acc, F, F@_1, F@_2, TrUserData) when N < 57 -> 'skip_length_delimited_openpoker.v1.TableEvent.DealtCards'(Rest, N + 7, X bsl N + Acc, F, F@_1, F@_2, TrUserData);
