verify_msg(Msg) when tuple_size(Msg) >= 1 -> verify_msg(Msg, element(1, Msg), []);
verify_msg(X) -> mk_type_error(not_a_known_message, X, []).

verify_msg(Msg, MsgName) when is_atom(MsgName) -> verify_msg(Msg, MsgName, []);
verify_msg(Msg, Opts) when tuple_size(Msg) >= 1 -> verify_msg(Msg, element(1, Msg), Opts);
verify_msg(X, _Opts) -> mk_type_error(not_a_known_message, X, []).

verify_msg(Msg, MsgName, Opts) ->
    TrUserData = proplists:get_value(user_data, Opts),
    case MsgName of
        'openpoker.v1.TableEvent.DealtCards' -> 'v_msg_openpoker.v1.TableEvent.DealtCards'(Msg, [MsgName], TrUserData);
        'openpoker.v1.TableEvent.MucksCards' -> 'v_msg_openpoker.v1.TableEvent.MucksCards'(Msg, [MsgName], TrUserData);
        'openpoker.v1.TableEvent.ShowsCards' -> 'v_msg_openpoker.v1.TableEvent.ShowsCards'(Msg, [MsgName], TrUserData);
        'openpoker.v1.TableEvent.PostAnte' -> 'v_msg_openpoker.v1.TableEvent.PostAnte'(Msg, [MsgName], TrUserData);
        'openpoker.v1.TableEvent.PostSmallBlind' -> 'v_msg_openpoker.v1.TableEvent.PostSmallBlind'(Msg, [MsgName], TrUserData);
        'openpoker.v1.TableEvent.PostBigBlind' -> 'v_msg_openpoker.v1.TableEvent.PostBigBlind'(Msg, [MsgName], TrUserData);
        'openpoker.v1.TableEvent.PostStraddle' -> 'v_msg_openpoker.v1.TableEvent.PostStraddle'(Msg, [MsgName], TrUserData);
        'openpoker.v1.TableEvent.PostDeadBlind' -> 'v_msg_openpoker.v1.TableEvent.PostDeadBlind'(Msg, [MsgName], TrUserData);
        'openpoker.v1.TableEvent.PostExtraBlind' -> 'v_msg_openpoker.v1.TableEvent.PostExtraBlind'(Msg, [MsgName], TrUserData);
        'openpoker.v1.TableEvent.Fold' -> 'v_msg_openpoker.v1.TableEvent.Fold'(Msg, [MsgName], TrUserData);
        'openpoker.v1.TableEvent.Check' -> 'v_msg_openpoker.v1.TableEvent.Check'(Msg, [MsgName], TrUserData);
        'openpoker.v1.TableEvent.Bet' -> 'v_msg_openpoker.v1.TableEvent.Bet'(Msg, [MsgName], TrUserData);
        'openpoker.v1.TableEvent.Raise' -> 'v_msg_openpoker.v1.TableEvent.Raise'(Msg, [MsgName], TrUserData);
        'openpoker.v1.TableEvent.Call' -> 'v_msg_openpoker.v1.TableEvent.Call'(Msg, [MsgName], TrUserData);
        'openpoker.v1.TableEvent.AddedChips' -> 'v_msg_openpoker.v1.TableEvent.AddedChips'(Msg, [MsgName], TrUserData);
